UPDATE /* OrgMgmtMapper.updateOrgMgmt */
       ORG_FAX_HST
SET RVISN_DTTM = SYSDATE
, RVISN_ID = #{rvisnId, jdbcType=VARCHAR} 
, APPL_CMPLT_DTTM = #{applCmpltDttm, jdbcType=VARCHAR} 
 WHERE ORGN_ID = #{orgnId}   
   AND FAX_SEQ_NUM = #{faxSeqNum}

UPDATE /* OrgMgmtMapper.updateOrgMgmtFax */
	   ORG_ORGN_INFO_MST
   SET FAX = #{fax, jdbcType=VARCHAR} 
 WHERE ORGN_ID = #{orgnId}

mapper.select:
/* org.orgmgmt.getAgncyInfo */ SELECT A.ORGN_ID , TO_CHAR(SYSDATE, 'YYYYMMDD') AS APPL_STRT_DT , TO_CHAR(SYSDATE - 1, 'YYYYMMDD') AS APPL_END_DT , A.ORGN_STAT_CD , A.TYPE_DTL_CD1 AS AGNCY_TYPE_CD , A.TYPE_DTL_CD2 AS AGNCY_TYPE_DTL_CD , A.TYPE_DTL_CD3 AS CHNL_DTL_CD , A.TYPE_DTL_CD AS MVNO_ORGN_YN , DECODE(A.OPEN_CRDT_LOAN_YN, '0', 'N', 'Y') AS OPEN_CRDT_LOAN_YN , DECODE(A.CMSN_PRVD_YN, '0', 'N', A.CMSN_PRVD_YN) AS CMSN_PRVD_YN , DECODE(A.HNDST_ORD_YN, '0', 'N', A.HNDST_ORD_YN) AS HNDST_ORD_YN , DECODE(A.HNDST_INVTR_YN, '0', 'N', A.HNDST_INVTR_YN) AS HNDST_INVTR_YN , DECODE(A.TAXBILL_YN, '0', 'N', A.TAXBILL_YN) AS TAXBILL_YN , DECODE(A.CLOSE_YN, '0', 'N', A.CLOSE_YN) AS CLOSE_YN , A.KT_ORG_ID , A.HGHR_ORGN_CD , #{regId} AS USER_ID , (SELECT NVL(MAX(CHG_SEQ), 1) FROM ORG_AGNCY_TYPE_HST WHERE ORGN_ID = #{orgnId} AND APPL_END_DT = '99991231') AS CHG_SEQ FROM ORG_ORGN_INFO_MST A WHERE A.TYPE_CD = '20'
AND A.TYPE_DTL_CD1 <> 'SU'
AND A.ORGN_ID = #{orgnId, jdbcType=VARCHAR}

