/* org.orgmgmt.updateAgncyTypeHst */
UPDATE ORG_AGNCY_TYPE_HST
SET
	APPL_END_DT = #{APPL_END_DT}
	, RVISN_ID = #{USER_ID}
	, RVISN_DTTM = SYSDATE
WHERE
	ORGN_ID = #{ORGN_ID}
	AND APPL_END_DT = '99991231'
	AND CHG_SEQ = #{CHG_SEQ}

mapper.insert:
/* org.orgmgmt.insertAgncyTypeHst */
INSERT INTO ORG_AGNCY_TYPE_HST (
	ORGN_ID
	, APPL_END_DT
	, CHG_SEQ
	, APPL_STRT_DT
	, ORGN_STAT_CD
	, AGNCY_TYPE_CD
	, AGNCY_TYPE_DTL_CD
	, CHNL_DTL_CD
	, MVNO_ORGN_YN
	, OPEN_CRDT_LOAN_YN
	, CMSN_PRVD_YN
	, HNDST_ORD_YN
	, HNDST_INVTR_YN
	, TAXBILL_YN
	, CLOSE_YN
	, KT_ORG_ID
	, HGHR_ORGN_CD
	, REGST_ID
	, REGST_DTTM
	, RVISN_ID
	, RVISN_DTTM
) VALUES (
	#{ORGN_ID}
	, '99991231'
	, ( SELECT NVL(MAX(CHG_SEQ) + 1, 1) FROM ORG_AGNCY_TYPE_HST WHERE ORGN_ID = #{ORGN_ID} AND APPL_END_DT = #{APPL_END_DT} )
	, #{APPL_STRT_DT}
	, #{ORGN_STAT_CD}
	, #{AGNCY_TYPE_CD}
	, #{AGNCY_TYPE_DTL_CD}
	, #{CHNL_DTL_CD}
	, #{MVNO_ORGN_YN}
	, #{OPEN_CRDT_LOAN_YN}
	, #{CMSN_PRVD_YN}
	, #{HNDST_ORD_YN}
	, #{HNDST_INVTR_YN}
	, #{TAXBILL_YN}
	, #{CLOSE_YN}
	, #{KT_ORG_ID}
	, #{HGHR_ORGN_CD}
	, #{USER_ID}
	, SYSDATE
	, #{USER_ID}
	, SYSDATE
)

